           }

           return false;
       }
   };
   ```



## 跳跃游戏（中等）

### 题目描述

给定一个长度为 `n` 的 **0 索引**整数数组 `nums`。初始位置为 `nums[0]`。每个元素 `nums[i]` 表示从索引 `i` 向前跳转的最大长度。换句话说，如果你在 `nums[i]` 处，你可以跳转到任意 `nums[i + j]` 处:`0 <= j <= nums[i]` 

- `i + j < n`

返回到达 `nums[n - 1]` 的最小跳跃次数。生成的测试用例可以到达 `nums[n - 1]`

### 题解

##### 预备知识

- `vector<int> a(2);` 是一个单独的vector对象，初始化大小为2。
- `vector<int> a[2];` 是一个长度为2的数组，数组中的每个元素都是一个独立的vector对象。（相当于定义两个数组）

##### 思路

###### 思路一：

先来讲一下lz自己的思路吧/(ㄒoㄒ)/~~（比较麻烦，但是确实做了好久）

同时进行一跳，比如在索引0位置时，索引0位置的值是3，那就同时进行0、1、2、3跳，然后存下这三跳的位置，再从这三跳再同时往下跳，期间为了减少缓存和运行时间，将每一跳到的位置存下来，如果之后有某一条跳到了该位置自动忽略，也就是每个点只跳一次

代码：

```c++
class Solution {
public:
    int jump(vector<int>& nums) {
        vector<int> node(10000, 0);
        vector<int> node2(10000, 0);
        vector<int> node3(10000, 0);
        int length=1;
        int lengthnext=0;
        int cnt=0;
        int n=nums.size();
        int i=0;
        if(n==1){
            return 0;
        }
        while(1){
            cnt++;
            for(i=0;i<length;i++){
                for(int j=0;j<=nums[node2[i]];j++){
                    if(node3[node2[i]+j]==1){
                        continue;
                    }
                    node[lengthnext]=node2[i]+j;
                    node3[node2[i]+j]=1;
                    if(node[lengthnext]==n-1){
                        return cnt;
                    }
                    lengthnext++;
                }
            }
            length=lengthnext;
            lengthnext=0;
            copy(node.begin(), node.begin()+length, node2.begin());
            }

        return 1;
    }
};
```

###### 思路二：

看了一下好像和lz的思路一致，只不过不用对要跳的格子数进行遍历，只记录一个范围（好像确实快很多！）

```c++
int jump(vector<int> &nums)
{
    int ans = 0;
    int start = 0;
    int end = 1;
    while (end < nums.size())
    {
        int maxPos = 0;
        for (int i = start; i < end; i++)
        {
            // 能跳到最远的距离
            maxPos = max(maxPos, i + nums[i]);
        }
        start = end;      // 下一次起跳点范围开始的格子
        end = maxPos + 1; // 下一次起跳点范围结束的格子
        ans++;            // 跳跃次数
    }
    return ans;
}
```

## 罗马数字转整数(简单)

### 题目描述

罗马数字包含以下七种字符: `I`， `V`， `X`， `L`，`C`，`D` 和 `M`。

```
字符          数值
I             1
V             5
X             10
L             50
C             100
D             500
M             1000
```

例如， 罗马数字 `2` 写做 `II` ，即为两个并列的 1 。`12` 写做 `XII` ，即为 `X` + `II` 。 `27` 写做 `XXVII`, 即为 `XX` + `V` + `II` 。

通常情况下，罗马数字中小的数字在大的数字的右边。但也存在特例，例如 4 不写做 `IIII`，而是 `IV`。数字 1 在数字 5 的左边，所表示的数等于大数 5 减小数 1 得到的数值 4 。同样地，数字 9 表示为 `IX`。这个特殊的规则只适用于以下六种情况：

- `I` 可以放在 `V` (5) 和 `X` (10) 的左边，来表示 4 和 9。
- `X` 可以放在 `L` (50) 和 `C` (100) 的左边，来表示 40 和 90。 
- `C` 可以放在 `D` (500) 和 `M` (1000) 的左边，来表示 400 和 900。

给定一个罗马数字，将其转换成整数。

### 题解

#### 思路

思路很简单，就是一个一个的比，比到I C X就注意一下

（看到一种更简单的，直接将对应值存在字典里，有两个字符的也一样）

#### 代码

```c++
class Solution {
public:
    int romanToInt(string s) {
        int sum=0;
        int length=s.size();
        for(int i=0;i<length;i++){
            switch(s[i]){
                case 'M':
                    sum+=1000;
                    break;
                case 'D':
                    sum+=500;
                    break;
                case 'C':
                    if(i<length-1&&(s[i+1]=='D'||s[i+1]=='M')){
                        if(s[++i]=='D'){
                            sum+=400;
                        }else{
                            sum+=900;
                        }
                    }else{
                        sum+=100;
                    }
                    break;
                case 'L':
                    sum+=50;
                    break;
                case 'X':
                    if(i<length-1&&(s[i+1]=='L'||s[i+1]=='C')){
                        if(s[++i]=='L'){
                            sum+=40;
                        }else{
                            sum+=90;
                        }
                    }else{
                        sum+=10;
                    }

                    break;
                case 'V':
                    sum+=5;
                    break;
                case 'I':
                    if(i<length-1&&(s[i+1]=='V'||s[i+1]=='X')){
                        if(s[++i]=='V'){
                            sum+=4;
                        }else{
                            sum+=9;
                        }
                    }else{
                        sum+=1;
                    }
                    break;
                default:
                    break;
            }
        }
        return sum;
    }
};
```

## 不同路径（中等）

### 题目描述

一个机器人位于一个 `m x n` 网格的左上角 （起始点在下图中标记为 “Start” ）。

机器人每次只能向下或者向右移动一步。机器人试图达到网格的右下角（在下图中标记为 “Finish” ）。

问总共有多少条不同的路径？

### 思路

#### 思路一：

深度优先，这是lz自己想到的方法但是会超时呜呜呜/(ㄒoㄒ)/~~

#### 思路二：

数学函数排列组合，向右向下的路径长度是知道的，用排列组合，假如到达终点需要向下三格向右六格，最大路径长度就相当于从九个需要的动作里选出两个（不要求顺序），但是由于lz用的c++，该方法会数值会超过限定

#### 思路三

动态规划：到达每一格的最大路径数量其实就是它的左边那一格和上面那一格的最大路径数量之和

我们只需要初始化边上的最大路径长度数量，由于在边缘，最大路径数量肯定是1

```c++
class Solution {
public:
    int uniquePaths(int m, int n) {
        int dp[m][n];
        for(int i=0;i<m;i++){
            dp[i][0]=1;
        }
        for(int i=0;i<n;i++){
            dp[0][i]=1;
        }
        for(int i=1;i<m;i++){
            for(int j=1;j<n;j++){
                dp[i][j]=dp[i][j-1]+dp[i-1][j];
            }
        }
        return dp[m-1][n-1];
    }
};
```

## 两个数组的交集（简单）

给定两个数组 `nums1` 和 `nums2` ，返回 *它们的交集* 。输出结果中的每个元素一定是 **唯一** 的。我们可以 **不考虑输出结果的顺序** 。

### 思路：简单遍历查找

首先对nums1去重，再对nums1的每个元素遍历，用find查找nums2是否有对应项

##### 代码

```c++
class Solution {
public:
    vector<int> intersection(vector<int>& nums1, vector<int>& nums2) {
        set<int>s(nums1.begin(), nums1.end());
        nums1.assign(s.begin(), s.end()); 
        vector<int> nums3;
        for(int i:nums1){
            if(find(nums2.begin(), nums2.end(), i) != nums2.end()){
                    nums3.push_back(i);
            }
        }
        return nums3;
    }
};
```

## 反转链表（简单）

### 知识点

普通结构体使用，可以用 **.**     当是用指针指向结构体时，使用->。 

eg: (*[node](https://so.csdn.net/so/search?q=node&spm=1001.2101.3001.7020)).data的作用等于node->data 

它们都是访问node指针所指向的结构体的data成员。*node是node这个地址里存的值，也就是一个结构体对象，所以你可以用点运算符来访问它的成员。而node是这个结构体的地址，所以你可以用箭头运算符来访问它所指向的对象的成员。箭头运算符是一种方便的写法，相当于先对指针进行解引用，然后再用点运算符。

### 思路

就是很简单的一个循环	

pos为当前位置，s指向pos前面一个，q指向pos的next，每次循环的时候让pos->=s;s=pos;pos=q如果这个时候pos为NULL了说明全部数据已经反制了，return s;如果还没有，继续让q=pos->next;

#### 代码

```c++
/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode(int x) : val(x), next(NULL) {}
 * };
 */
class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        if(head==NULL){
            return NULL;
        }
        ListNode *s=NULL;
        ListNode *q=head;
        ListNode *p=q->next;
        while(1){
            q->next=s;
            s=q;
            q=p;
            if(q==NULL){
                return s;
            }
            p=q->next;
        }
    }
};
```

## 把字符串转换为整数（中等）

### 题目描述

写一个函数 StrToInt，实现把字符串转换成整数这个功能。不能使用 atoi 或者其他类似的库函数。

首先，该函数会根据需要丢弃无用的开头空格字符，直到寻找到第一个非空格的字符为止。

当我们寻找到的第一个非空字符为正或者负号时，则将该符号与之后面尽可能多的连续数字组合起来，作为该整数的正负号；假如第一个非空字符是数字，则直接将其与之后连续的数字字符组合起来，形成整数。

该字符串除了有效的整数部分之后也可能会存在多余的字符，这些字符可以被忽略，它们对于函数不应该造成影响。

注意：假如该字符串中的第一个非空格字符不是一个有效整数字符、字符串为空或字符串仅包含空白字符时，则你的函数不需要进行转换。

在任何情况下，若函数不能进行有效的转换时，请返回 0。

**说明：**

假设我们的环境只能存储 32 位大小的有符号整数，那么其数值范围为 [−231, 231 − 1]。如果数值超过这个范围，请返回  INT_MAX (231 − 1) 或 INT_MIN (−231) 。

### 知识点

1、C++字符数字怎么转换为整数型数字	

```c++
char s='2';
int num=int(s)-48;
cout<<num;




输出：2
```

2、C++没有求幂的运算符，

c++头文件加 #include<math.h>
使用pow(x,y)，可算出x的y次幂

### 思路

首先获取去除前面的空格，然后比较第一个字符是否为正负号或者在0到九之间，不在就返回零，接着如果有正负号就记录下来，再去除前面的0，将每一个字符转换为数字存在num数组里，如果发现了不为数字的直接跳出循环，我这里就直接让i=length了，接着判断num的长度，大于10直接判定超出了范围，但是等于10的也可能超出范围了，就用longlong定义sum，可以保存更大的值以判断超出范围

```c++
class Solution {
public:
    int strToInt(string str) {
        int length=str.size();
        int i=0;
        int fuhao=0;
        vector<int> num;
        while(i<length&&str[i]==' '){
                i++;
        }
        if((str[i]!='-'&&str[i]!='+'&&(str[i]<'0'||str[i]>'9'))||i==length){
            return 0;
        }
        if(str[i]=='-'||str[i]=='+'){
            if(str[i]=='-'){
                fuhao=1;
            }
            i++;
        }
        while(i<length&&str[i]=='0'){
                i++;
        }
        if(i==length){
            return 0;
        }
        for(;i<length;i++){
            if(str[i]>='0'&&str[i]<='9')
            {
                num.push_back(int(str[i])-48);
            }else{
                i=length;
            }
        }
        length=num.size();
        if(length>10){
            if(fuhao==0){
                return INT_MAX;
            }else{
                return INT_MIN;
            }
        }
        long long sum=0;
        for(auto number : num){
            sum+=number*pow(10,--length);
        }
        if(sum>=2147483648){
            if(fuhao==0){
                return INT_MAX;
            }else{
                return INT_MIN;
            }
        }
        if(fuhao==0){
            return sum;
        }else{
            return -sum;
        }

    }
};
```

